const items = $input.all();

function parseOutput(output) {
  if (output && typeof output === 'object') {
    return {
      verdict: String(output.verdict ?? '').toUpperCase(),
      reason: String(output.reason ?? '').trim(),
      memory_used: Boolean(output.memory_used),
      parsed: output,
    };
  }

  const text = String(output ?? '').trim();

  try {
    const obj = JSON.parse(text);
    return {
      verdict: String(obj?.verdict ?? '').toUpperCase(),
      reason: String(obj?.reason ?? '').trim(),
      memory_used: Boolean(obj?.memory_used),
      parsed: obj,
    };
  } catch {}

  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      const obj = JSON.parse(jsonMatch[0]);
      return {
        verdict: String(obj?.verdict ?? '').toUpperCase(),
        reason: String(obj?.reason ?? '').trim(),
        memory_used: Boolean(obj?.memory_used),
        parsed: obj,
      };
    } catch {}
  }

  const verdictMatch = text.match(/\b(SPAM|NOT_SPAM)\b/i);
  const verdict = verdictMatch ? verdictMatch[1].toUpperCase() : '';
  return {
    verdict,
    reason: text.slice(0, 240),
    memory_used: /qdrant|memory/i.test(text),
    parsed: null,
  };
}

return items
  .map((item) => {
    const parsed = parseOutput(item?.json?.output);
    return {
      json: {
        ...item.json,
        verdict: parsed.verdict,
        reason: parsed.reason || item?.json?.reason || '',
        memory_used: parsed.memory_used || Boolean(item?.json?.memory_used),
        output_parsed: parsed.parsed ?? item?.json?.output_parsed ?? null,
      },
      pairedItem: item.pairedItem,
    };
  })
  .filter((item) => item.json.verdict === 'SPAM');

const items = $input.all();
const total = items.length;
let spam = 0;
let notSpam = 0;
let unknown = 0;
let memoryUsed = 0;

const samples = items.slice(0, 5).map((item, i) => {
  const output = item?.json?.output;
  const asText = typeof output === 'string' ? output : JSON.stringify(output ?? {});
  const text = String(asText).trim();
  const verdict = typeof output === 'object'
    ? String(output?.verdict ?? '').toUpperCase()
    : (text.match(/\b(SPAM|NOT_SPAM)\b/i)?.[1] || '').toUpperCase();

  if (verdict === 'SPAM') spam += 1;
  else if (verdict === 'NOT_SPAM') notSpam += 1;
  else unknown += 1;

  const usedMemory = typeof output === 'object'
    ? Boolean(output?.memory_used)
    : /qdrant|memory/i.test(text);
  if (usedMemory) memoryUsed += 1;

  return { index: i, verdict: verdict || 'UNKNOWN', usedMemory, preview: text.slice(0, 240) };
});

return [{
  json: {
    total,
    spam,
    notSpam,
    unknown,
    memoryUsed,
    samples
  }
}];

const items = $input.all();

function firstString(...values) {
  for (const value of values) {
    if (value === null || value === undefined) continue;
    const text = String(value).trim();
    if (text) return text;
  }
  return '';
}

function normalizeLabels(labels) {
  if (!Array.isArray(labels)) return [];
  return labels
    .map((label) => {
      if (label && typeof label === 'object') {
        const id = firstString(label.id, label.name);
        const name = firstString(label.name, label.id);
        return { id, name };
      }
      const value = firstString(label);
      return { id: value, name: value };
    })
    .filter((label) => label.id || label.name);
}

function boolValue(value) {
  if (value === true || value === false) return value;
  const text = String(value ?? '').trim().toLowerCase();
  return ['true', 'yes', '1'].includes(text);
}

function parseOutput(output) {
  if (output && typeof output === 'object') {
    return {
      verdict: firstString(output.verdict).toUpperCase(),
      reason: firstString(output.reason),
      memory_used: boolValue(output.memory_used),
      parsed: output,
      raw: JSON.stringify(output),
    };
  }

  const text = String(output ?? '').trim();
  const cleaned = text.replace(/^\x60\x60\x60(?:json)?\s*/i, '').replace(/\x60\x60\x60$/i, '').trim();

  for (const candidate of [cleaned, cleaned.match(/\{[\s\S]*\}/)?.[0]]) {
    if (!candidate) continue;
    try {
      const obj = JSON.parse(candidate);
      return {
        verdict: firstString(obj?.verdict).toUpperCase(),
        reason: firstString(obj?.reason),
        memory_used: boolValue(obj?.memory_used),
        parsed: obj,
        raw: text,
      };
    } catch {}
  }

  const lineMatch = cleaned.match(/\b(NOT_SPAM|SPAM)\b\s*(?:\||:|-)?\s*([\s\S]*)$/i);
  const verdict = lineMatch ? lineMatch[1].toUpperCase() : '';
  const reason = firstString(lineMatch?.[2], cleaned.slice(0, 240));
  return {
    verdict,
    reason,
    memory_used: /qdrant|memory/i.test(cleaned),
    parsed: null,
    raw: text,
  };
}

return items
  .map((item) => {
    const source = item.json ?? {};
    const parsed = parseOutput(source.output);
    const verdict = firstString(source.verdict, parsed.verdict).toUpperCase();

    if (verdict !== 'SPAM') {
      return null;
    }

    const sourceLabels = normalizeLabels(source.sourceLabels ?? source.labels ?? source.labelIds);
    const sourceMessageId = firstString(source.sourceMessageId, source.messageId, source.id);
    const sourceFrom = firstString(source.sourceFrom, source.From, source.from);
    const sourceSubject = firstString(source.sourceSubject, source.Subject, source.subject);
    const sourceSnippet = firstString(source.sourceSnippet, source.snippet);
    const reason = firstString(source.reason, parsed.reason, 'none');

    const memoryText = [
      `from: ${sourceFrom}`,
      `subject: ${sourceSubject}`,
      `snippet: ${sourceSnippet}`,
      `verdict: ${verdict}`,
      `reason: ${reason}`,
      `labels: ${JSON.stringify(sourceLabels)}`,
    ].join('\n');

    return {
      json: {
        ...source,
        memoryText,
        messageId: sourceMessageId,
        verdict,
        reason,
        modelMemoryUsed: parsed.memory_used || Boolean(source.memory_used),
        sourceFrom,
        sourceSubject,
        sourceSnippet,
        sourceLabels,
      },
      pairedItem: item.pairedItem,
    };
  })
  .filter(Boolean);

