}

function inferRouteMailbox(to, sourceMailbox) {
  const text = [to, sourceMailbox].join(' ').toLowerCase();
  if (text.includes('customerservice')) return 'customerservice';
  if (text.includes('oneserverx')) return 'oneserverx';
  if (text.includes('lester')) return 'lester';
  return 'unknown';
}

function inferSourceMailbox(routeMailbox, to) {
  if (routeMailbox === 'customerservice') return 'customerservice@aitradeengines.com';
  if (routeMailbox === 'oneserverx') return 'lesterajohn@oneserverx.com';
  if (routeMailbox === 'lester') return 'LesterAJohn@gmail.com';
  return firstString(to);
}

return items
  .map((item) => {
    const source = item.json ?? {};
    const sourceLabels = normalizeLabels(source.sourceLabels ?? source.labels ?? source.labelIds);
    const labelText = sourceLabels.map((label) => [label.id, label.name].join(' ')).join(' ').toUpperCase();
    const hasSpamLabel = labelText.includes('SPAM');

    if (!hasSpamLabel) {
      return null;
    }

    const sourceMessageId = firstString(source.sourceMessageId, source.messageId, source.id);
    const sourceThreadId = firstString(source.sourceThreadId, source.threadId);
    const sourceFrom = firstString(source.sourceFrom, source.From, source.from);
    const sourceTo = firstString(source.sourceTo, source.To, source.to);
    const sourceSubject = firstString(source.sourceSubject, source.Subject, source.subject);
    const sourceSnippet = firstString(source.sourceSnippet, source.snippet, source.textPlain, source.textHtml);
    const routeMailbox = firstString(source.routeMailbox, inferRouteMailbox(sourceTo, source.sourceMailbox));
    const sourceMailbox = firstString(source.sourceMailbox, inferSourceMailbox(routeMailbox, sourceTo));
    const reason = 'Existing Gmail SPAM label harvested for FortisAI spam memory';

    const memoryText = [
      'source: gmail_spam_label_harvest',
      `mailbox: ${sourceMailbox}`,
      `routeMailbox: ${routeMailbox}`,
      `messageId: ${sourceMessageId}`,
      `threadId: ${sourceThreadId}`,
      `from: ${sourceFrom}`,
      `to: ${sourceTo}`,
      `subject: ${sourceSubject}`,
      `snippet: ${sourceSnippet}`,
      'verdict: SPAM',
      `reason: ${reason}`,
      `labels: ${JSON.stringify(sourceLabels)}`,
    ].join('\n');

    return {
      json: {
        ...source,
        routeMailbox,
        sourceMailbox,
        sourceMessageId,
        sourceThreadId,
        sourceFrom,
        sourceTo,
        sourceSubject,
        sourceSnippet,
        sourceLabels,
        id: sourceMessageId || source.id || '',
        messageId: sourceMessageId || source.messageId || source.id || '',
        threadId: sourceThreadId || source.threadId || '',
        From: sourceFrom,
        To: sourceTo,
        Subject: sourceSubject,
        snippet: sourceSnippet,
        labels: sourceLabels,
        verdict: 'SPAM',
        reason,
        memoryText,
        metadata: {
          source: 'gmail_spam_label_harvest',
          routeMailbox,
          sourceMailbox,
          messageId: sourceMessageId,
          threadId: sourceThreadId,
          from: sourceFrom,
          to: sourceTo,
          subject: sourceSubject,
          labels: sourceLabels,
        },
      },
      pairedItem: item.pairedItem,
    };
  })
  .filter(Boolean);
